INSERT INTO public.photos VALUES (22836, 'Academia General Militar c.1981', 'Fundada en 1927 por el dictador Miguel Primo de Rivera, es el centro de formaciâ”œâ”‚n superior de todo el ejâ”œÂ®rcito de tierra de Espaâ”œâ–’a. Su primer director fue el luego tambiâ”œÂ®n dictador Francisco Franco. El ministro de Guerra Manuel Azaâ”œâ–’a la cerrâ”œâ”‚ en 1931, pero Franco la reabriâ”œâ”‚ en 1940. Allâ”œÂ¡ han estudiado tanto Juan Carlos de Borbâ”œâ”‚n como su hijo Felipe. La estatua ecuestre que se aprecia en el centro representa a Francisco Franco. Fue donada por el Ayuntamiento de Zaragoza en 1948 y retirada en 2006. El nuevo plan de estudios de 1973 establecâ”œÂ¡a que la AGM pasaba a ser el primer centro de enseâ”œâ–’anza del Ejâ”œÂ®rcito de Tierra. La necesidad de alojar a mâ”œÃ­s tropa hizo insuficiente las capacidades del complejo original. Un nuevo proyecto dispuso, por ello, la construcciâ”œâ”‚n de nuevos inmuebles, en varias fases, que aparecen al fondo de la imagen. En diciembre de 1980 quedâ”œâ”‚ inaugurado el nuevo Servicio de Alimentaciâ”œâ”‚n para tropa, cadetes y mandos, en un gran edificio con la cocina en el centro, rodeada por los comedores, caracterâ”œÂ¡stico por sus porches, a la derecha de la imagen.', 1981, 1981, 1981, 'Anos 80', NULL, 41.69952500, -0.87188200, '0101000020E610000006137F1475E6EBBF01DE02098AD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14813267099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14813267099.webp', 'https://www.flickr.com/photos/zaragozaantigua/14813267099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22886, 'Santa Isabel c.1980', 'El barrio rural de Santa Isabel en una vista aâ”œÂ®rea capturada desde el este y sobrevolando en primer tâ”œÂ®rmino la antigua carretera a Villamayor de Gâ”œÃ­llego, actual avenida del Real Zaragoza. Se mantiene la estructura del barrio vertebrado fundamentalmente en torno a la carretera de Madrid a Francia, actual avenida de Santa Isabel, y con un caserâ”œÂ¡o caracterizado de forma mayoritaria por tradicionales viviendas unifamiliares. Modernos bloques, algunos en proceso de construcciâ”œâ”‚n, como el inmediato a la iglesia parroquial de Santa Isabel de Portugal, empiezan a surgir de forma aislada, de forma mâ”œÃ­s acusada en la zona cercana al puente sobre el râ”œÂ¡o Gâ”œÃ­llego, donde tambiâ”œÂ®n destaca la vertical estampa de la Harinera del barrio. Al fondo, tras el cauce fluvial, la discontinua urbanizaciâ”œâ”‚n de la Margen Izquierda de Zaragoza, desde Vadorrey hasta el Actur. El templo del Pilar emerge a la izquierda mâ”œÃ­s extrema. Fuente: Zaragoza en imâ”œÃ­genes, CAZAR, 1980.', 1980, 1980, 1980, 'Anos 80', NULL, 41.66654500, -0.82485600, '0101000020E61000009C19FD683865EABFFA27B85851D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20074129790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20074129790.webp', 'https://www.flickr.com/photos/zaragozaantigua/20074129790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
