INSERT INTO public.photos VALUES (22942, 'Carretera de Madrid 1983', 'Captura visual realizada durante la ceremonia oficial de colocaciâ”œâ”‚n de la primera piedra del nuevo recinto de la Feria de Muestras de Zaragoza, en la carretera de Madrid, frente a la Venta de los Caballos, el primaveral domingo 10 de abril de ese aâ”œâ–’o. Siguiendo la tradiciâ”œâ”‚n, sobre esa piedra se colocâ”œâ”‚ el hormigonado pilar de la imagen con una inscripciâ”œâ”‚n que reza (sin una coma, ni media): "Aquâ”œÂ¡ se colocâ”œâ”‚ la primera piedra para la nueva Feria Oficial y Nacional de Muestras siendo alcalde de Zaragoza el ilustrâ”œÂ¡simo seâ”œâ–’or don Ramâ”œâ”‚n Sâ”œÃ­inz de Varanda y presidente de la Instituciâ”œâ”‚n y de la Câ”œÃ­mara de Comercio e Industria el ilustrâ”œÂ¡simo seâ”œâ–’or don Josâ”œÂ® Luis Martâ”œÂ¡nez Candial. Abril de 1983." Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1983, 1983, 1983, 'Anos 80', NULL, 41.62951200, -0.97865000, '0101000020E6100000705F07CE1951EFBF433866D993D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33251392676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33251392676.webp', 'https://www.flickr.com/photos/zaragozaantigua/33251392676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23092, 'Rolling Stones 2003', 'Foto: Josâ”œÂ® Miguel Marco. Lunes 29 de septiembre de 2003, explanada de la Feria de Muestras de Zaragoza. Concierto de The Rolling Stones. En la foto, Mick Jagger. Fuente: www.josemiguelmarco.com/', 2003, 2003, 2003, 'Siglo XXI', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20902392306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20902392306.webp', 'https://www.flickr.com/photos/zaragozaantigua/20902392306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23139, 'Cuarto Cinturâ”œâ”‚n 2006', 'Foto: Juan Carlos Arcos. El Cuarto Cinturâ”œâ”‚n de ronda de Zaragoza (Z-40) avanza en sus obras en esta vista aâ”œÂ®rea de 2006. En primer plano, campos del barrio rural de Movera. Al fondo, el râ”œÂ¡o Ebro, a su paso por la huerta de Las Fuentes (arriba a la derecha). Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.65728500, -0.84106300, '0101000020E61000004F05DCF3FCE9EABF609335EA21D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31821519421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31821519421.webp', 'https://www.flickr.com/photos/zaragozaantigua/31821519421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23145, 'Parque PLAZA 2006', 'Foto: Esther Casas. Estructura de la atalaya del parque lineal de PLAZA (Plataforma Logâ”œÂ¡stica de Zaragoza), durante su construcciâ”œâ”‚n en 2006, junto al Canal Imperial de Aragâ”œâ”‚n. Este gigantesco parque, de cuatro kilâ”œâ”‚metros de largo y 62 hectâ”œÃ­reas, se inaugurâ”œâ”‚ en mayo de 2007. Era la â”œÂ®poca de hacer cosas enormes, sin previsiâ”œâ”‚n de uso alguno y con presupuestos endiablados. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.65404700, -0.98337000, '0101000020E6100000B9C2BB5CC477EFBF0186E5CFB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31953342436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31953342436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31953342436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23147, 'Shakira 2006', 'Foto: Marina Ovejero. La cantante colombiana Shakira fue elegida por la organizaciâ”œâ”‚n de la Expo 2008 para promocionarla dos aâ”œâ–’os antes. Estuvo varios dâ”œÂ¡as en Zaragoza, terminando con un concierto el 14 de junio de 2006 en la Feria de Muestras, que iniciâ”œâ”‚ su gira "Fijaciâ”œâ”‚n oral". Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.62951200, -0.97865000, '0101000020E6100000705F07CE1951EFBF433866D993D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31979673695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31979673695.webp', 'https://www.flickr.com/photos/zaragozaantigua/31979673695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23182, 'Aeropuerto c.2001', 'Imagen de un aviâ”œâ”‚n de transporte norteamericano modelo Douglas C-47 Skytrain abandonado en el aeropuerto de Zaragoza durante un cuarto de siglo hasta que en 2003 fue desmontado y trasladado al Aeromuseo de Mâ”œÃ­laga, donde fue restaurado con la apariencia de una aeronave de transporte de pasajeros de la compaâ”œâ–’â”œÂ¡a Iberia entre 1955 y 1977. La vida â”œâ•‘til de este aviâ”œâ”‚n comenzâ”œâ”‚ en 1945 en las fuerzas aâ”œÂ®reas norteamericanas, siendo luego cedido al Ejâ”œÂ®rcito del Aire espaâ”œâ–’ol hasta finales de los aâ”œâ–’os 70.', 2001, 2001, 2001, 'Siglo XXI', NULL, 41.66201100, -1.00490500, '0101000020E6100000DC63E9431714F0BFCF4BC5C6BCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50938298611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50938298611.webp', 'https://www.flickr.com/photos/zaragozaantigua/50938298611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23215, 'Riada 2015', 'Foto: Yeresi Arnal. Vista aâ”œÂ®rea de la riada o crecida del Ebro en marzo de 2015. Al fondo, el noroeste de Zaragoza, siguiendo el curso ascendente de la inundaciâ”œâ”‚n, bordeando los montes de El Castellar. Abajo se aprecia el encauzamiento del râ”œÂ¡o a su paso por la ciudad. Fuente: www.soydezaragoza.es', 2015, 2015, 2015, 'Siglo XXI', NULL, 41.69350100, -0.91856000, '0101000020E6100000863DEDF0D764EDBF245F09A4C4D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40492042624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40492042624.webp', 'https://www.flickr.com/photos/zaragozaantigua/40492042624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23406, 'Ermita de Santa Bâ”œÃ­rbara 1750', 'Tras unas tremendas tormentas con enorme aparato elâ”œÂ®ctrico, fue fundada en 1690 la cofradâ”œÂ¡a de la Gloriosa Santa Bâ”œÃ­rbara, por agricultores de la parroquia de San Pablo temerosos por sus cultivos, y erigieron una ermita en honor a esa Santa en lo alto de uno de los esteparios vales de Valdespartera, sobre terreno poco estable, y con precarios materiales de la zona, de forma que cada poco tiempo eran necesarias reparaciones. El templo es descrito como modesto, de una sola nave y dos altares, uno dedicado a la santa titular, y otro al Santo Cristo. En el tejado, una espadaâ”œâ–’a con "cimbalico" o pequeâ”œâ–’a campana. Ante la puerta de entrada, un "pilâ”œâ”‚n" o "peirâ”œâ”‚n" culminado con una cruz de hierro. Adosada detrâ”œÃ­s estaba la vivienda del ermitaâ”œâ–’o, de dos alturas. Por la notable distancia con la ciudad, su momento culminante era la anual romerâ”œÂ¡a, cada primero de mayo. Asâ”œÂ¡ fue hasta que el reordenamiento parroquial de 1905 dejâ”œâ”‚ a la ermita sin ermitaâ”œâ–’o, ni romerâ”œÂ¡a, y sin las periâ”œâ”‚dicas reparaciones, con lo que el edificio fue entrando en progresiva ruina, y hacia 1946 fue desmantelado lo poco que quedaba. En la imagen, dibujo que recrea esta ermita de Santa Bâ”œÃ­rbara, rodeada de contrafuertes para reforzar su precaria estructura. A la izquierda, la vivienda del ermitaâ”œâ–’o, en el centro, la ermita propiamente dicha, y a la derecha, el "peirâ”œâ”‚n". Al fondo, y abajo, quedarâ”œÂ¡an Valdespartera y Zaragoza. Fuente visual: plenaszaragoza.blogspot.com.es/', 1750, 1750, 1750, 'Siglo XIX', NULL, 41.61564200, -0.94103600, '0101000020E61000001C7A8B87F71CEEBFA305685BCDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19499821869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19499821869.webp', 'https://www.flickr.com/photos/zaragozaantigua/19499821869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23407, 'Monasterio de Santa Fe 1998', 'Monasterio de Santa Fe de Zaragoza, acuarela de Teodoro Pâ”œÂ®rez Bordetas, 1998. Fuente: www.aragonesasi.com', 1998, 1998, 1998, 'Anos 90', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19575966445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19575966445.webp', 'https://www.flickr.com/photos/zaragozaantigua/19575966445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23408, 'Arcosur 2009', 'Vista del terreno explanado para la construcciâ”œâ”‚n de la urbanizaciâ”œâ”‚n Arcosur de Zaragoza, en junio de 2009. Abajo, Valdespartera y Montecanal. Al fondo, la Feria de Muestras y la Plataforma Logâ”œÂ¡stica PLAZA. Este barrio gigante del suroeste de Zaragoza fue defendido en el Ayuntamiento por el alcalde Josâ”œÂ® Atarâ”œÂ®s en 2003, y criticado por Juan Alberto Belloch, en la oposiciâ”œâ”‚n. En 2004, cuando se decidiâ”œâ”‚ que la Expo Zaragoza 2008 se ubicarâ”œÂ¡a en el Meandro de Ranillas, el Ayuntamiento no tenâ”œÂ¡a dinero suficiente para comprar todos esos terrenos. Asâ”œÂ¡ que Ibercaja desembolsâ”œâ”‚ los 70 millones de euros necesarios para la adquisiciâ”œâ”‚n. A cambio, el Ayuntamiento le daba a la entidad financiera el suelo para promover 2.000 viviendas en Arcosur. Fuente: www.arcosur-zaragoza.com/', 2009, 2009, 2009, 'Siglo XXI', NULL, 41.62853100, -0.96130300, '0101000020E6100000787E5182FEC2EEBFD7C22CB473D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894706096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894706096.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894706096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23411, 'Venta de los Caballos 1999', 'Vista aâ”œÂ®rea del circuito de karts "Kartâ”œâ”‚dromo Aragâ”œâ”‚n", anexo al restaurante Venta de los Caballos, clausurado en 2009. Al fondo, la Feria de Muestras (1986) y su aparcamiento. Estos terrenos, en el km. 311 de la carretera de Madrid (ahora autovâ”œÂ¡a), fueron comprados en 2004 por Plaza (Plataforma Logâ”œÂ¡stica de Zaragoza) por 6,3 millones de euros, para que se hiciera por allâ”œÂ¡ el acceso al centro comercial Plaza Imperial. Cinco aâ”œâ–’os antes fueron tasados en 154.000 euros. Presuntamente, el dueâ”œâ–’o del terreno pagâ”œâ”‚ una comisiâ”œâ”‚n ilegal a los gestores pâ”œâ•‘blicos de 661.000 euros. Fuente: Colecciâ”œâ”‚n particular.', 1999, 1999, 1999, 'Anos 90', NULL, 41.63210600, -0.98665600, '0101000020E6100000A0DE8C9AAF92EFBF7DCD72D9E8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24112575679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24112575679.webp', 'https://www.flickr.com/photos/zaragozaantigua/24112575679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23419, 'R.E.M. 2005', 'Foto: Josâ”œÂ® Miguel Marco. Sâ”œÃ­bado, 28 de mayo de 2005. R.E.M., el grupo estadounidense de rock alternativo (1980-2011), actâ”œâ•‘a en la Feria de Muestras de Zaragoza. En la foto, su cantante, Michael Stipe. Fuente: Heraldo de Aragâ”œâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31829092241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31829092241.webp', 'https://www.flickr.com/photos/zaragozaantigua/31829092241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23421, 'Recintos feriales 2006', 'Foto: Esther Casas. Aunque en Zaragoza los enclaves que no tienen dos o mâ”œÃ­s denominaciones son poco comunes, la alusiâ”œâ”‚n al "recinto ferial" puede referirse a dos lugares bien distintos: por un lado, los solares donde se asientan los feriantes nâ”œâ”‚madas con sus atracciones y circos; y por otro, los recintos permanentes en los que se celebran las ferias de muestras. En la foto panorâ”œÃ­mica de agosto de 2006, explanaciâ”œâ”‚n de los terrenos del nuevo recinto ferial (de atracciones) de Valdespartera, comenzado a usar en 2007, y al fondo, gracias a la ausencia de construcciones en el barrio de Arcosur, vista hacia el oeste del recinto ferial de la Feria de Muestras, en la confluencia del Cuarto Cinturâ”œâ”‚n con la autovâ”œÂ¡a a Madrid. En todo caso, ferias. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.61920000, -0.93911800, '0101000020E6100000BBB72231410DEEBF73D712F241CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31997418666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31997418666.webp', 'https://www.flickr.com/photos/zaragozaantigua/31997418666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23427, 'Monasterio de Santa Fe c.1893', 'Interesante imagen del monasterio cisterciense de Santa Fe de Huerva en un contraste con el despejado entorno y el fondo de los montes de Cuarte. Se trata de una construcciâ”œâ”‚n barroca que data del siglo XVIII y que transformâ”œâ”‚ radicalmente el original convento establecido a mediados del siglo XIV. Destaca su monumental iglesia, construida en formas y escala barroca en el â”œâ•‘ltimo tercio del siglo XVIII, con gran câ”œâ•‘pula sobre el crucero y torre alzada a la diestra de su ingreso principal, y el muro perimetral que delimitaba el conjunto. Abandonado desde la exclaustraciâ”œâ”‚n de 1835, en el momento de realizar esta captura las cubiertas de la iglesia ya aparecen hundidas.', 1893, 1893, 1893, 'Siglo XIX', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49060726156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49060726156.webp', 'https://www.flickr.com/photos/zaragozaantigua/49060726156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23761, 'Puente Z-40 2007', 'Vista aâ”œÂ®rea de las obras de construcciâ”œâ”‚n del puente del Cuarto Cinturâ”œâ”‚n o autovâ”œÂ¡a de circunvalaciâ”œâ”‚n Z-40 sobre el râ”œÂ¡o Ebro, entre el barrio de Movera (izquierda) y los terrenos entre Las Fuentes y La Cartuja (derecha). Comenzâ”œâ”‚ a construirse en 2005 y se inaugurâ”œâ”‚ en junio de 2008. Fuente visual: Archivo El Periâ”œâ”‚dico de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.63183200, -0.83964000, '0101000020E6100000E73A8DB454DEEABF7C48F8DEDFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21842420741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21842420741.webp', 'https://www.flickr.com/photos/zaragozaantigua/21842420741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23661, 'Jura AGM 1942', 'Imagen capturada por los reporteros grâ”œÃ­ficos alemanes destacados en la decembrina y solemne Jura de Bandera de Caballeros Cadetes en la Academia General Militar, con motivo del retorno de la histâ”œâ”‚rica bandera que en 1886 bordâ”œâ”‚ con sus humanas manos la regente doâ”œâ–’a Marâ”œÂ¡a Cristina, y que tras el cierre de la Academia durante la Segunda Repâ”œâ•‘blica, habâ”œÂ¡a permanecido guardada en una vitrina. El director y fundador de la Academia en su nueva ubicaciâ”œâ”‚n zaragozana, ahora casualmente Caudillo por la gracia de dios, la entregâ”œâ”‚ de nuevo a su entonces director, el general Hidalgo de Cisneros, en una ceremonia con inaudita pasarela de las autoridades polâ”œÂ¡ticas del momento (militares, religiosas, civiles, y jerarquâ”œÂ¡as del Movimiento). Mientras, en un lejano recodo de la estepa euroasiâ”œÃ­tica junto al râ”œÂ¡o Volga, ruge la descomunal batalla que pondrâ”œÃ­ patas arriba la guerra en la que Espaâ”œâ–’a era formalmente "no beligerante", aunque con simpatâ”œÂ¡as algo mâ”œÃ­s que fuertes hacia el amigo Eje Roma-Berlâ”œÂ¡n-Tokio. Mientras, en el cercano San Juan de Mozarrifar, junto al Gâ”œÃ­llego, seguâ”œÂ¡a funcionando, como desde 1938, el campo de concentraciâ”œâ”‚n para prisioneros de guerra allâ”œÂ¡ habilitado, donde la antigua fâ”œÃ­brica papelera de "Las Navas". Fuente visual: Berliner Verlag Archiv (Agencia EFE)', 1942, 1942, 1942, 'Anos 40', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24667332695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24667332695.webp', 'https://www.flickr.com/photos/zaragozaantigua/24667332695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23663, 'Aerâ”œâ”‚dromo Sanjurjo 1939', 'Imagen del Sturzkampfflugzeug (bombardero en picado) Junkers Ju-87 de la serie B-1 ("Bertha") durante una parada militar realizada en el aerâ”œâ”‚dromo Sanjurjo de Zaragoza. Matriculado con la referencia "29-11" este fue uno de los cinco aparatos de la novâ”œÂ¡sima serie "Bertha" que de este moderno aeroplano de guerra fueron incorporados por los alemanes a la Legiâ”œâ”‚n Câ”œâ”‚ndor para combatir contra la Repâ”œâ•‘blica Espaâ”œâ–’ola desde finales del aâ”œâ–’o 1938 en escenarios bâ”œÂ®licos de Lâ”œÂ®rida, Barcelona, Tarragona y Valencia. Dibujado en el carenado tren de aterrizaje izquierdo destaca el dibujo de la rosada cerdita "Jolanthe", mamâ”œÂ¡fero artiodâ”œÃ­ctilo cuyo personaje daba tâ”œÂ¡tulo a la popular pelâ”œÂ¡cula alemana del gâ”œÂ®nero comedia româ”œÃ­ntica titulada "Krach um Jolanthe" (Problemas con Jolanthe), que ademâ”œÃ­s prestâ”œâ”‚ su nombre a una de las primeras "Kette" (formaciâ”œâ”‚n de combate compuesta por tres aviones) de Stukas operativas en combate real sobre cielos espaâ”œâ–’oles: la Kette Jolanthe. Al fondo, en formaciâ”œâ”‚n de revista, algunos de los "Pedros" o bombarderos Heinkel He-111 B-1 que operaban desde esta plurinacionalista base aâ”œÂ®rea. Fuente visual: elhangardetj.blogspot.com.es/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26442014858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26442014858.webp', 'https://www.flickr.com/photos/zaragozaantigua/26442014858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23667, 'Carretera de Huesca 1938', 'Imagen capturada por un soldado alemâ”œÃ­n de la Legiâ”œâ”‚n Câ”œâ”‚ndor destinado a la base aâ”œÂ®rea de Sanjurjo, en el militarizado puesto de control instalado en la carretera de Huesca, unos 200 metros despuâ”œÂ®s del acceso principal a la Academia General Militar, junto a la estaciâ”œâ”‚n transformadora de Elâ”œÂ®ctricas Reunidas de Zaragoza S.A. allâ”œÂ¡ ubicada. Entre la dotaciâ”œâ”‚n que custodia este puesto, una pareja de la Guardia Civil, y miembros de Acciâ”œâ”‚n Ciudadana de Zaragoza. Mientras la barrera permanece bajada, un convoy en direcciâ”œâ”‚n a Zaragoza pasando inspecciâ”œâ”‚n. Fuente: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', NULL, 41.70165300, -0.86758600, '0101000020E610000066F50EB743C3EBBFF511F8C3CFD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30946046941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30946046941.webp', 'https://www.flickr.com/photos/zaragozaantigua/30946046941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23671, 'Aerâ”œâ”‚dromo Sanjurjo 1937', 'Imagen capturada desde la altura de un bombardero alemâ”œÃ­n Heinkel-111 B-1 durante la maniobra de aterrizaje en el aerâ”œâ”‚dromo zaragozano de Sanjurjo. Sobre las pistas posan al menos otros quince "Pedros", denominaciâ”œâ”‚n indâ”œÂ¡gena de este moderno modelo aeronaâ”œâ•‘tico que, en nâ”œâ•‘mero de 100, formâ”œâ”‚ parte del contingente de la Legiâ”œâ”‚n Câ”œâ”‚ndor llegado como solidaridad militar desde el III Reich con los nacionalistas sublevados contra la Repâ”œâ•‘blica. En uno de los aparatos se visualiza el sâ”œÂ¡mbolo de identificaciâ”œâ”‚n pintado en lugar de la reglamentaria esvâ”œÃ­stica. Fuente visual: "Condor: The Luftwaffe in Spain, 1936-39".', 1937, 1937, 1937, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32091312901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32091312901.webp', 'https://www.flickr.com/photos/zaragozaantigua/32091312901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23675, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Posado del contingente radicado en el zaragozano aerâ”œâ”‚dromo de Sanjurjo de la "Aviazione Legionaria", o unidades de la Regia Aeronautica italiana enviadas por Mussolini en agosto de 1936 en apoyo de los nacionalistas sublevados en armas contra la Repâ”œâ•‘blica democrâ”œÃ­tica. Al fondo, aviones de caza italianos CR-20 y CR-32 "Freccia/Chirri". Unas semanas despuâ”œÂ®s, sus camaradas destinados en la base aâ”œÂ®rea de Logroâ”œâ–’o volaron por la ruta de la carretera de Zaragoza, en aparatos Savoia-Marchetti S-79 hasta la localidad bajoaragonesa de Alcaâ”œâ–’iz, y la arrasaron, tal que diez meses y una semana antes habâ”œÂ¡a sucedido con Gernika. Mâ”œÃ­s adelante, este tipo de acciones serâ”œÃ­n consideradas "bombardeos terroristas". Fuente visual: revista "Vida Aragonesa".', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34415745475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34415745475.webp', 'https://www.flickr.com/photos/zaragozaantigua/34415745475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23677, 'Ctra. de Huesca 1928', 'Imagen capturada durante la construcciâ”œâ”‚n de uno de los pabellones principales de la Academia General Militar junto a la carretera de Huesca, proyectada por los ingenieros militares Mariano Lafiguera, Vicente Rodrâ”œÂ¡guez y Antonio Parelladas en formas historicistas y neomudâ”œÂ®jares. Fuente visual: Academia General Militar. 90 aâ”œâ–’os de presencia en Zaragoza, Luis Alfonso Arcarazo Garcâ”œÂ¡a, IFC, 2017.', 1928, 1928, 1928, 'Anos 20', NULL, 41.69949300, -0.87190200, '0101000020E6100000CC24EA059FE6EBBFF56393FC88D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37697787465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37697787465.webp', 'https://www.flickr.com/photos/zaragozaantigua/37697787465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23682, 'Ctra. de Huesca 1930', 'Imagen capturada desde la carretera de Zaragoza a Huesca y centrada en la gran fachada principal de la Academia General Militar, inaugurada hacâ”œÂ¡a poco con diseâ”œâ–’o de los ingenieros militares Mariano Lafiguera, Vicente Rodrâ”œÂ¡guez y Antonio Parelladas. Esta fachada presenta una llamativa alternancia de edificios de tres alturas con torreones de cuatro y cinco pisos, estos â”œâ•‘ltimos flanqueando el ingreso al Patio de Armas. A la derecha, bloque de alojamientos con capacidad para 400 efectivos de tropa y 250 caballerâ”œÂ¡as. Justo antes del ingreso, incipientes jardines de la Reina Marâ”œÂ¡a Cristina.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69915200, -0.87137400, '0101000020E6100000E5B512BA4BE2EBBF6C770FD07DD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48195809011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48195809011.webp', 'https://www.flickr.com/photos/zaragozaantigua/48195809011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24096, 'Maginot y Franco 1930', 'Imagen capturada en el patio central de la Academia General Militar y centrada en la presencia de altura del ministro de la guerra de Francia, general Andrâ”œÂ® Maginot. Junto a â”œÂ®l, el director de la instituciâ”œâ”‚n, general Francisco Franco Bahamonde. Ademâ”œÃ­s, y entre otros, el capitâ”œÃ­n general de la regiâ”œâ”‚n militar, Jorge Fernâ”œÃ­ndez de Heredia; el gobernador civil, Juan Dâ”œÂ¡az Caneja; el gobernador militar, general de divisiâ”œâ”‚n Agustâ”œÂ¡n Gâ”œâ”‚mez Morato. El batallâ”œâ”‚n de cadetes de la academia, con su bandera, mâ”œâ•‘sica y banda de cornetas, rindiâ”œâ”‚ honores a Maginot interpretando la Marsellesa. Tras el preceptivo desfile de tropas, visitâ”œâ”‚ las instalaciones de la academia, terminando en un almuerzo trufado de discursos oficiales, culminado con la imposiciâ”œâ”‚n al director de las insignias de comendador de la Legiâ”œâ”‚n de Honor por sus mâ”œÂ®ritos en el desembarco de Alhucemas (1925). Finalmente, saludâ”œâ”‚ a los representantes de la colonia francesa en la ciudad y visitâ”œâ”‚ a continuaciâ”œâ”‚n el templo del Pilar antes de regresar a Francia por la carretera de Navarra. Este ministro, fallecido en 1932, ha pasado a la historia por impulsar el proyecto de construcciâ”œâ”‚n de una lâ”œÂ¡nea estâ”œÃ­tica de fortificaciones en la frontera con Alemania que, denominada "Lâ”œÂ¡nea Maginot", fue rebasada sin demasiados problemas por el ejâ”œÂ®rcito de la Alemania nazi en 1940.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69915200, -0.87137400, '0101000020E6100000E5B512BA4BE2EBBF6C770FD07DD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49881848736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49881848736.webp', 'https://www.flickr.com/photos/zaragozaantigua/49881848736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24099, 'Ctra. de Pastriz 1959', 'Imagen de la procesiâ”œâ”‚n que desde el barrio rural de Movera se encamina por la carretera del Puente de Santa Isabel a Pastriz para llegar hasta la Torre de Santa Engracia. La fotografâ”œÂ¡a se centra en la cabecera de la procesiâ”œâ”‚n, con el Santo Cristo al frente, tallado por el escultor villalenguino Genaro Lâ”œÃ­zaro Gumiel, y la prâ”œÃ­ctica totalidad de los lugareâ”œâ–’os detrâ”œÃ­s. Hacia el fondo, volquete habilitado como carroza donde la imagen de Nuestra Seâ”œâ–’ora de Movera es transportada junto con niâ”œâ–’as y niâ”œâ–’os en trâ”œÃ­nsito hacia su Primera Comuniâ”œâ”‚n. Esta imagen se ha capturado a la altura, a la derecha, del actual inmueble del nâ”¬â•‘ 473 de la avenida de Movera que, junto con las inmediatas parcelas gemelas de los nâ”œâ•‘meros 469 y 471 perduran, si bien algo remodeladas.', 1959, 1959, 1959, 'Anos 50', NULL, 41.64796700, -0.81996200, '0101000020E6100000DDCEBEF2203DEABF91F12895F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50769637908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50769637908.webp', 'https://www.flickr.com/photos/zaragozaantigua/50769637908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
