INSERT INTO public.photos VALUES (25082, 'AGM 1955', 'Jura de bandera del prâ”œÂ¡ncipe Juan Carlos de Borbâ”œâ”‚n en la Academia General Militar (el primero de la fila, junto al cura), en diciembre de 1955. 25 aâ”œâ–’os despuâ”œÂ®s, ya rey, renovarâ”œÃ­ su juramento, a los cinco dâ”œÂ¡as del golpe de Estado fallido de 1981. Fuente: "Historia de la Academia General Militar".', 1955, 1955, 1955, 'Anos 50', NULL, 41.69949300, -0.87190200, '0101000020E6100000CC24EA059FE6EBBFF56393FC88D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30110442278.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30110442278.webp', 'https://www.flickr.com/photos/zaragozaantigua/30110442278/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25084, 'Feria de Muestras 1989', 'Imagen capturada durante la oficial inauguraciâ”œâ”‚n de la 49â”¬Â¬ ediciâ”œâ”‚n de la Feria de Muestras de Zaragoza, en octubre de ese aâ”œâ–’o, en las recientes instalaciones de la carretera nacional II, Madrid-Zaragoza-Barcelona. En ella se nos muestran, de izquierda a derecha, el brazo izquierdo de Pascual Marco Sebastiâ”œÃ­n (PSOE), vicepresidente de la DPZ; junto a â”œÂ®l, Josâ”œÂ® Luis Martâ”œÂ¡nez Candial, presidente de Ibercaja (hasta 1988, Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”œâ”‚n y Rioja), y de la Câ”œÃ­mara de Comercio e Industria de Zaragoza; Hipâ”œâ”‚lito Gâ”œâ”‚mez de las Roces (PAR), presidente de la DGA; tras â”œÂ®l, Santiago Lanzuela; a su lado, Carlos Pâ”œÂ®rez Anadâ”œâ”‚n (PSOE), delegado del Gobierno en Aragâ”œâ”‚n y gobernador Civil; Juan Bautista Monserrat Mesanza (CDS), presidente de las Cortes de Aragâ”œâ”‚n; Antonio Gonzâ”œÃ­lez Triviâ”œâ–’o (PSOE), alcalde de Zaragoza; Luis Acâ”œÂ¡n Boned (PAR), consejero de Industria, Comercio y Turismo de la DGA; y Luis Garcâ”œÂ¡a Nieto (PSOE), primer teniente de Alcalde y concejal de Urbanismo del ayuntamiento de Zaragoza. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1989, 1989, 1989, 'Anos 80', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30751700766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30751700766.webp', 'https://www.flickr.com/photos/zaragozaantigua/30751700766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25086, 'Base Aâ”œÂ®rea 1963', 'Simpâ”œÃ­tica imagen del alcalde Luis Gâ”œâ”‚mez Laguna encasquetâ”œÃ­ndose un casco de piloto en la Base Aâ”œÂ®rea donde desde 1958 estaba radicada la Fuerza Aâ”œÂ®rea de los Estados Unidos (de Norteamâ”œÂ®rica). Le ayuda en las labores un sargento tâ”œÂ®cnico forano antes de subirse, posiblemente, a uno de los reactores "F-102A Delta Dagger" del "431st Test and Evaluation Squadron" (los "Red Devils", o "Demonios Rojos"), cazas interceptores de la primera lâ”œÂ¡nea de defensa ante las flotas de bombarderos nucleares soviâ”œÂ®ticos que amenazaban la civilizaciâ”œâ”‚n occidental y el modo de vida norteamericano. Poco despuâ”œÂ®s, Stanley Kubrick dirigirâ”œÂ¡a el sensato delirio "Dr. Strangelove, or How I Learned to Stop Worrying and Love the Bomb". Tal vez Luis Gâ”œâ”‚mez Laguna compartiera durante su visita de la imagen alguna anâ”œÂ®cdota de cuando, a finales de los aâ”œâ–’os 30, hizo de traductor para la germana Legiâ”œâ”‚n Câ”œâ”‚ndor establecida en esos mismos pagos. O no. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1963, 1963, 1963, 'Anos 60', NULL, 41.67786400, -1.06798100, '0101000020E610000072FDBB3E7316F1BF60915F3FC4D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31596163733.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31596163733.webp', 'https://www.flickr.com/photos/zaragozaantigua/31596163733/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25170, 'Estaciâ”œâ”‚n Aula Dei 1946', '"Estaciâ”œâ”‚n de biologâ”œÂ¡a experimental de Cogullada. Aspecto general". Teodoro Râ”œÂ¡os Balaguer, 1946. Dibujo del proyecto de edificios para la Estaciâ”œâ”‚n Experimental creada en 1944 en Cogullada, que se trasladarâ”œÃ­ junto a la Cartuja de Aula Dei en 1952. Pese a conservar en el proyecto su denominaciâ”œâ”‚n hasta 1948, el grâ”œÃ­fico representa los terrenos de la avenida de Montaâ”œâ–’ana, en Peâ”œâ–’aflor. Fuente: Historia de la Estaciâ”œâ”‚n Experimental de Aula Dei, 2014.', 1946, 1946, 1946, 'Anos 40', NULL, 41.72462200, -0.81198400, '0101000020E61000002A029CDEC5FBE9BF26FBE769C0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33055338430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33055338430.webp', 'https://www.flickr.com/photos/zaragozaantigua/33055338430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25196, 'Cartuja de N.â”¬Â¬ S.â”¬Â¬ de Aula Dei 1852', 'Dibujo de la planta, cortes y alzados de la Cartuja de Nuestra Seâ”œâ–’ora de Aula Dei trazados por Miguel Blasco. Segâ”œâ•‘n la disposiciâ”œâ”‚n de la planta, el norte quedarâ”œÂ¡a a la derecha. En 1564 se habâ”œÂ¡a puesto la primera piedra del conjunto, inmediato al camino de Peâ”œâ–’aflor de Gâ”œÃ­llego, en el tâ”œÂ®rmino de El Regado. En 1835 el inmueble habâ”œÂ¡a sido desamortizado, y dos aâ”œâ–’os despuâ”œÂ®s pertenecâ”œÂ¡a a Juan Francisco Clarac, que destinâ”œâ”‚ el recinto a fâ”œÃ­brica de sedas. Durante el resto del siglo XIX cambiâ”œâ”‚ de propietario varias veces. Fuente visual: Cartuja de N.â”¬Â¬ S.â”¬Â¬ de Aula Dei, AHPZ.', 1852, 1852, 1852, 'Siglo XIX', NULL, 41.73175800, -0.81231000, '0101000020E61000001FD7868A71FEE9BF0E4B033FAADD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27386739158.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27386739158.webp', 'https://www.flickr.com/photos/zaragozaantigua/27386739158/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25539, 'Galacho de Juslibol 2012', 'Foto: Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n, 2012. Vista del galacho de Juslibol, meandro abandonado por el râ”œÂ¡o Ebro en la crecida del 2 de enero de 1961. Fuente: peripaseos.wordpress.com/2012/04/13/montes-de-juslibol/', 2012, 2012, 2012, 'Siglo XXI', NULL, 41.70572300, -0.92852000, '0101000020E61000004AD235936FB6EDBF7B849A2155DA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19295487273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19295487273.webp', 'https://www.flickr.com/photos/zaragozaantigua/19295487273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
