INSERT INTO public.photos VALUES (21484, 'Cardenal Soldevila 1926', '1926. Gerardo Alcaâ”œâ–’iz. "Mausoleo del Cardenal Soldevila". El cuatro de junio de 1923, el coche del Cardenal Soldevila, matrâ”œÂ¡cula Z-135, se detuvo frente a la reja de la escuela-asilo de las hermanas de San Vicente de Paâ”œâ•‘l en la calle Terminillo. El cardenal habâ”œÂ¡a fundado la instituciâ”œâ”‚n, y era su principal valedor. Todas las tardes repetâ”œÂ¡a la misma rutina, segâ”œâ•‘n voces porque mantenâ”œÂ¡a una relaciâ”œâ”‚n con una de las monjas, a la que legâ”œâ”‚ parte de su fortuna, lo que ella aprovechâ”œâ”‚ para volver al estado civil. Mientras esperaba para entrar, Ã”Ã‡Â£Los SolidariosÃ”Ã‡Ã˜ Francisco Ascaso y Rafael Liberato se plantaron junto al coche y vaciaron sus armas. El châ”œâ”‚fer y el mayordomo resultaron heridos, el cardenal muriâ”œâ”‚ en el acto. Si para la gente de orden el cardenal Soldevila era merecedor de todos los honores (Senador Vitalicio, Gran Cruz de Isabel la Catâ”œâ”‚lica, Hijo Adoptivo de Zaragoza...), para los medios obreros de la ciudad su figura se identificaba directamente con la corrupciâ”œâ”‚n y el terrorismo patronal y de Estado, en los convulsos aâ”œâ–’os 20. Tras su asesinato, el cardenal Soldevila fue enterrado en el Pilar, enfrente de la capilla de la Virgen. La escuela-asilo de las hermanas paulas sigue en la calle "La Milagrosa", a pocos metros del Hospital Clâ”œÂ¡nico Universitario. Desde entonces, en el patio del recreo el monolito de la foto seâ”œâ–’alaba el lugar del atentado hasta 2024, cuando fue trasladado al patio del Cedro del palacio Arzobispal. Zaragoza perdiâ”œâ”‚ a su cardenal y nunca lo ha vuelto a recuperar. En la imagen, el monumento al cardenal Soldevila en el lugar de autos. Los que sonrâ”œÂ¡en son sospechosos.', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.64452000, -0.90479400, '0101000020E6100000A9BEF38B12F4ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974761721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974761721.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974761721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21535, 'Dictador y alcalde 1929', 'El dictador Miguel Primo de Rivera y el alcalde de Zaragoza, Miguel Alluâ”œÂ® Salvador (1927-1929), en la inauguraciâ”œâ”‚n del parque Primo de Rivera, el 17 de mayo de 1929. Fuente: Eloy Fernâ”œÃ­ndez Clemente, "Gente de orden", Ibercaja, 1995.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63714200, -0.89751100, '0101000020E6100000B29B19FD68B8ECBF3A747ADE8DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527938614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527938614.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527938614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21805, 'Cementerio Terminillo 1935', 'El cementerio de Terminillo, Miralbueno, o de la Casa Blanca, fue un temporal camposanto de efâ”œÂ¡mera vida prâ”œÃ­ctica (1864-1866), producto de la reacciâ”œâ”‚n del crecido clericalismo polâ”œÂ¡tico tras el Concordato de 1851. Fue concebido como cementerio 100% parroquial, para arrebatar al ayuntamiento la gestiâ”œâ”‚n del negocio de la muerte, y privatizarla en beneficio propio. En esta aventura se embarcaron 13 de las 15 parroquias de la ciudad. Este cementerio fue ubicado en una irracional localizaciâ”œâ”‚n al suroeste de la ciudad, en el Tâ”œÂ®rmino de Miralbueno, partida del Viâ”œâ–’edo Viejo, entre el camino de la Mosquetera, un brazal de riego del Canal Imperial denominado "de la Cabra", y el camino hacia el puente de Medio. En los poco mâ”œÃ­s de dos aâ”œâ–’os de funcionamiento, casi 3.500 restos humanos fueron allâ”œÂ¡ depositados, entre nichos y enterramientos. Tras su clausura, los restos fueron exhumados y llevados al municipal cementerio de Torrero, y el terreno quedâ”œâ”‚ sin uso. En 1914 fue vendido en pâ”œâ•‘blica subasta, por un montante de 19.211,50 pesetas, al arzobispo Juan Soldevila, que allâ”œÂ¡ fundâ”œâ”‚ poco despuâ”œÂ®s la Escuela-Asilo de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, o "monjas del cardenal". Allâ”œÂ¡ encontrarâ”œÂ¡a la muerte en 1923. En la imagen, plano parcelario del Instituto Geogrâ”œÃ­fico y Catastral de 1935 en el que hemos coloreado la rectangular â”œÃ­rea donde se ubicâ”œâ”‚ este cementerio. A su izquierda, la lâ”œÂ¡nea del ferrocarril de Caminreal. Al sur, el camino a los nuevos depâ”œâ”‚sitos de agua. Al norte, fuera de plano, el riego y camino de la Mosquetera. En la actualidad, este lugar se ubica al nordeste del cruce de la avenida de San Juan Bosco, y la Vâ”œÂ¡a Universitas. Fuente: Ramâ”œâ”‚n Betrâ”œÃ­n Abadâ”œÂ¡a, "La Ciudad y los muertos. La formaciâ”œâ”‚n del Cementerio de Torrero" (2015)', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64418300, -0.90571700, '0101000020E6100000A7CCCD37A2FBECBFD0D1AA9674D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28213420285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28213420285.webp', 'https://www.flickr.com/photos/zaragozaantigua/28213420285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21880, 'Monumento escolares caâ”œÂ¡dos 1936', 'Imagen de la maqueta proyectada por Regino Borobio y Fâ”œÂ®lix Burriel para el "Monumento a los Escolares muertos por la Patria 1936", que en su versiâ”œâ”‚n definitiva serâ”œÂ¡a denominado "Monumento a los Escolares muertos por Dios y por Espaâ”œâ–’a 1936-39". Se construyâ”œâ”‚ en 1941 en "La gran plaza de las Facultades" del Campos de la nueva plaza de San Francisco, proyectada como de Espaâ”œâ–’a, y asâ”œÂ¡ redenominada tras 1936, frente a la Facultad de Derecho, quedando la de Filosofâ”œÂ¡a y Letras a la izquierda, y la de Ciencias, a la derecha. Sobre un soporte hormigonado y revestido con piedra blanca de las canteras de La Puebla de Albortâ”œâ”‚n, se levantâ”œâ”‚ una horizontal pantalla de sillares con el escudo de la Universidad en el centro, sobre el que se imprimiâ”œâ”‚ la leyenda que da nombre al monumento, y que aparece flanqueado ademâ”œÃ­s por dos parejas de escolares militarizados y tres guirnaldas en piedra a cada lado, como perenne muestra de homenaje. Cada 9 de febrero en este monumento se celebraba el Dâ”œÂ¡a del Estudiante Caâ”œÂ¡do, ceremonia establecida en 1938 por el gobierno faccioso para conmemorar la muerte violenta de un estudiante falangista inmediatamente convertido en protomâ”œÃ­rtir, que el franquismo institucionalizâ”œâ”‚. En 1981, tras unos aâ”œâ–’os en el limbo, fue finalmente desmontado y recompuesto en el patio principal del acuartelamiento de San Fernando en una versiâ”œâ”‚n reducida que sâ”œâ”‚lo incluâ”œÂ¡a a las figuras de los escolares-soldados. Los sillares sobrantes fueron trasladados a la Comandancia de obras del Cuartel de Valdespartera. En la actualidad no es fâ”œÃ­cil saber dâ”œâ”‚nde, ni en quâ”œÂ® estado, se encuentran los restos de este monumento, ni quiâ”œÂ®n vela por ellos. Fuente visual: Mâ”œâ”‚nica Vâ”œÃ­zquez Astorga, Anales de Historia del Arte, 2006.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64262800, -0.89672600, '01010000