INSERT INTO public.photos VALUES (21969, 'Feria de Muestras 1944', 'Una imagen promocional de la Feria de Muestras al atardecer, ya inaugurada la torre, con su iluminaria, terminada para el certamen de ese aâ”œâ–’o. Este punto de vista escogido por el fotâ”œâ”‚grafo, hacia el suroeste, contrasta sobremanera en un entorno sin mâ”œÃ­s edificaciones, y despoblado, en el lâ”œÂ¡mite de la Zaragoza del momento. A la izquierda, el paseo de Isabel la Catâ”œâ”‚lica Fuente: www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22809690438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22809690438.webp', 'https://www.flickr.com/photos/zaragozaantigua/22809690438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
